sp_widget.link:
function(scope) {
	$(document).ready(function() {

		$('#createTicketModal').on('hide.bs.modal', function () {
			scope.data.categories = null;
			scope.data.items = null;


		//Dismiss remove autofill url if aplicable
		if(window.location.toString().indexOf("autofill=true") != -1){
			window.location.href = "?id="+ scope.data.page;
		}



		});

		$('[data-toggle="popover"]').popover();


	});
}

sp_widget.script:
(function() {

    data.cfmScript = gs.getProperty("case.feedback.module");

    data.trackingEnabled = gs.getProperty('EQIX_ANALYTICS_SEGMENT_ENABLED');
    data.categoriesTrackingEnabled = gs.getProperty('EQIX_ANALYTICS_CATEGORIES_ENABLED');

    data.page = $sp.getParameter("id");
    data.country = '';
    data.reassociationIDs = gs.getProperty("EQUIX_Reassociation_Services");
    data.reassociationAddOnServiceID = gs.getProperty("EQIX_MH_Transfer_Add-on_Service");

    data.assignAddOnSummaryWidget = $sp.getWidget('assign_addon_summary', '');
    data.requestCategory = gs.getProperty("EQIX_Managed_Services_Catalog_Request");
    data.incidentCategory = gs.getProperty("EQIX_Managed_Services_Catalog_Trouble");

    data.instanceProd = gs.getProperty('glide.servlet.uri').includes("https://equinixcsm.service-now.com/") ? false : true;
    //
