    function getParentCategoryType(sys_id) {
        var gr = new GlideRecord("sc_category");
        gr.addActiveQuery();
        gr.addQuery("sc_catalog", catalog_sys_id);
        gr.addQuery("sys_id", sys_id);
        gr.addNullQuery("parent");
        gr.query();
        if (gr.next()) {
            if (gr.getValue("sys_id") != data.request_category_sys_id) {
                return 1; // Trouble
            }
        }

        return 0; // Request
    }

    function checkOffBusinessHours() { //Nether Land Business Hours

        var gdt = new GlideDateTime();
        gdt.setTimeZone("Europe/Amsterdam");
        var gdtcurrent = gdt.getDisplayValue();

        var gdcurrent = gdtcurrent.toString().substring(0, 11);
        var gdtstart = new GlideDateTime(gdcurrent + ' 08:00:00');
        var gdtend = new GlideDateTime(gdcurrent + ' 18:00:00');
        var inRange = (gdtcurrent >= gdtstart && gdtcurrent <= gdtend) ? true : false;

        var gdx = new GlideDateTime(gdtcurrent);
        var day = gdx.getDayOfWeek(); // Get Day of the week

        if (day == 6 || day == 7) {
            return true;
        }
        if ((day == 1 || day == 2 || day == 3 || day == 4 || day == 5)) {
            if (!inRange)
                return true;

        }

    }


    function verifyMDRProduct(input_catalog_item_sys_id, product_line_parameter) {
        if (input_catalog_item_sys_id) {
            if (gs.getProperty('EQIX.MDR.newCase.productLine') == input_catalog_item_sys_id || gs.getProperty('EQIX.PRODUCT.MDR.CATALOG.TROUBLE.SYS_ID') == input_catalog_item_sys_id)
                data.selectedProductIsMDR = true;
            else
                data.selectedProductIsMDR = false;
        }

        if (product_line_parameter) {
            if (gs.getProperty('EQIX.MDR.newCase.productLine') == product_line_parameter || gs.getProperty('EQIX.PRODUCT.MDR.CATALOG.TROUBLE.SYS_ID') == product_line_parameter)
                data.selectedProductIsMDR = true;
            else
                data.selectedProductIsMDR = false;
        }
    }

    var grCoreCountry = new GlideRecord("core_country");
    grCoreCountry.addQuery("iso3166_2", operatingUnit);
    grCoreCountry.query();

    var country_sys_id = '';
    if (grCoreCountry.next()) {
        country_sys_id = grCoreCountry.getValue("sys_id");
    }

    data.nameLinkUpgrade = gs.getMessage('I want to upgrade one of my services');
    data.showlinkUpgrade = new EQIX_Sales_Portal_Utils().checkIsAvailableUpgradeProducts(country_sys_id);

    var ibx = "";
    var grGetIBXbyAtr = new GlideRecord("sn_customerservice_contract_item_attributes");
    grGetIBXbyAtr.addEncodedQuery("u_attribute=IBX^u_contract_item.account=" + account);
    grGetIBXbyAtr.setLimit(1);
    grGetIBXbyAtr.query();
    if (grGetIBXbyAtr.next()) {
        ibx = grGetIBXbyAtr.getValue('u_value');
    } else {
        var grContractItem = new GlideRecord("sn_customerservice_contract_item");
        //grContractItem.addEncodedQuery('u_order_line_itemISNOTEMPTY^account='+account); ESS2-145
        grContractItem.addEncodedQuery('u_order_line_item.u_ibxISNOTEMPTY^account=' + account);
        grContractItem.setLimit(1);
        grContractItem.query();

        if (grContractItem.next()) {
            ibx = grContractItem.u_order_line_item.u_ibx.name;
        } else {
			//***ESS2-145***
            var grContractCI = new GlideRecord("contract_rel_ci");
            grContractCI.addEncodedQuery('ci_item.locationISNOTEMPTY^contract.account=' + account);
            grContractCI.setLimit(1);
            grContractCI.query();

            if (grContractCI.next()) {
                ibx = grContractCI.ci_item.location.getDisplayValue();
            }
        }
    }

    if (!gs.nil(ibx)) {
        var grAccount = new GlideRecord("customer_account");

        if (grAccount.get(account)) {
            var countryGr = grAccount.getValue("country");
            var account_number = grAccount.getValue("u_account_number");

            var priceResponse = new EQIX_POE_Pricing().getPremierPrice(account_number, ibx);

            if (gs.nil(priceResponse)) {
                data.service_cost = gs.getMessage('There is no catalog price for this Service request, please raise a "question" request to get the price.');
                return;
            }

            if (gs.nil(priceResponse.product)) {
                data.service_cost = gs.getMessage('There is no catalog price for this Service request, please raise a "question" request to get the price.');
                return;
            }

            var currency = priceResponse.product.currency;
            var priceList = priceResponse.product.price;
            var price = '';

            priceList.forEach(function(p) {
                if (p.PartNumber == 'MGD00017.ELEM' && p.ProductDescription == 'Managed Services Premier Support Hour')
                    if (!gs.nil(p.PriceList)) {
                        price = p.PriceList[0].amount;
                    }

            });

            if (!gs.nil(price)) {
                var currency_symbol = "";
                //Get Country by AccountID

                //Get Currency
                var grSysLocale = new GlideRecord('sys_locale');
                grSysLocale.addEncodedQuery("country=" + countryGr + "^currency_code=" + currency);
                grSysLocale.query();

                if (grSysLocale.next()) {
                    currency_symbol = grSysLocale.getValue('currency_symbol');
                }

                var args = [currency_symbol, price];

                data.service_cost = gs.getMessage("For Service requested, you will be charged", args);
            } else {
                data.service_cost = gs.getMessage('There is no catalog price for this Service request, please raise a "question" request to get the price.');
            }

        } else {
            data.service_cost = gs.getMessage('There is no catalog price for this Service request, please raise a "question" request to get the price.');

        }

    }

